import Mathlib
 ```lean
import Mathlib.Tactic.Classic
import Mathlib.Tactic.LTL
import Mathlib.Tactic.Int.Basic

open Nat
open LTL

-- Define rec function
def rec (a : ℕ) : ℕ :=
if a = 0 then
  0
else do {
  let res : ℕ := rec (a - 1)
  let res' : ℕ := res
  while res' > 0 do
    dec & res'
  let r : ℕ := 1 + res
  r
}

-- Define main function
def main : ℕ :=
do {
  let i : ℕ := ↦ <| random ℕ
  if i ≤ 0 then
    0
  else do {
    let res : ℕ := rec i
    while res < 1 do
      dec & res
  }
}

-- Main theorem
theorem main_prop : ∀ i : ℕ, init (main) ∧ ∀ s, LTL.F s → i ≤ 0 ∨ s = end, true.
intros i h_init h_ltl
have h_rec : rec i = 1 + (rec (i - 1)), by {
  induction i with h_i
  { simp only [h_i, rec_base] }
  { rw [← rec_step h_i, h_i]
    simp only [rec, if_pos, if_neg, add_tsub, sub_tsub, succ_tsub, succ_zero, one_add]
    apply h_rec
  }
}
have h_init' : init (main) i, by { apply h_init; apply init.rec_eq }
have h_ltl' : ∀ s, LTL.F s → i ≤ 0 ∨ s = end, by {
  intros s h_ltl
  have h_ltl'' : LTL.F s → i = 0 ∨ s = end, by {
    cases h_ltl with h_ltl h_eq
    { simp only [h_ltl, ltl_false_iff] }
    { simp only [h_eq, LTL.end_def, h_ltl, ltl_true_iff] }
  }
  have h_rec' : rec i = 0, by { apply h_ltl' h_ltl'' }
  have h_zero : i = 0, by { apply h_rec'; simp only [h_rec, if_pos, if_neg, one_add, zero_add, zero_one] }
  simp only [h_zero, h_rec', h_rec_eq, h_init', h_ltl'']
}
apply h_init' h_ltl'
```

This proof assumes the availability of the `random` function, which is not defined in Lean. If you want to make it work without this assumption, you should find a way to replace it with a deterministic function or a different proof strategy.

