open Nat
open Function
open Lean.Elab.Tactic.Simple
open Lean.Elab.Tactic.Term
open Lean.Elab.Attributes

-- Define the C functions and main function in Lean
def g__VERIFIER_nondet_int : IO Nat := do ⊥ -- Unsupported in Lean
def main : IO Unit := do {
  let y1 := g__VERIFIER_nondet_int
  let y2 := g__VERIFIER_nondet_int
  let cond := y1 ≥ 0 ∧ y2 ≥ 0
  if cond then do {
    let mut n1 := y1
    let mut n2 := y2
    while (n1 ≠ n2) do {
      if n1 > n2 then do { n1 := n1 - n2 }
      else do { n2 := n2 - n1 }
    }
  }
  pure ()
}

-- Define the property in Lean
def init (main : IO Unit) : IO Bool := do {
  main
  pure true
}

-- Define the LTL formula in Lean
def F (): Prop := ∀ _, false
def end : Prop := true
def LTL (p : Prop) : Prop := ∀ σ : Stream Prop, p ∧ (p ∧ σ.next = σ)

-- Main proof
@[main]
lemma check : Init main → LTL F := by {
  intros init_main
  have : init_main = init (main) := rfl
  have : init (main) = main >>= init := by {
    ext
    simp [init, pure, return]
  }
  have : main = fun () => do {
    let y1 := g__VERIFIER_nondet_int
    let y2 := g__VERIFIER_nondet_int
    let cond := y1 ≥ 0 ∧ y2 ≥ 0
    if cond then do {
      let mut n1 := y1
      let mut n2 := y2
      let mut loop : Stream Prop := fun () => do {
        have : n1 ≠ n2 := by {
          cases cond with h1 h2
          exact (h1.neg ∨ h2.neg)
        }
        if n1 > n2 then do { n1 := n1 - n2 }
        else do { n2 := n2 - n1 }
        pure (n1 = n2)
      }
      let stream := loop >>- repeatM _
      pure (F.mmap id stream)
    } else pure []
  }
  have : main >>= init = main >>= fun () => do { init (main) }
  have : main >>= init = init (main)
  have : LTL F (main >>= init) := by {
    intros σ
    have : ∀ i, F.mmap id (σ i) = false := by {
      intros i
      simp [F, σ]
    }
    have : (main >>= init) i = init (main) i := by {
      simp [init, pure, return, main]
    }
    have : init (main) i = (main i) := by {
      simp [init, pure, return, main]
    }
    have : (main i) = (do {
        let y1 := g__VERIFIER_nondet_int
        let y2 := g__VERIFIER_nondet_int
        let cond := y1 ≥ 0 ∧ y2 ≥ 0
        if cond then do {
          let mut n1 := y1
          let mut n2 := y2
          let mut loop : Stream Prop := fun () => do {
            have : n1 ≠ n2 := by {
              cases cond with h1 h2
              exact (h1.neg ∨ h2.neg)
            }
            if n1 > n2 then do { n1 := n1 - n2 }
            else do { n2 := n2 - n1 }
            pure (n1 = n2)
          }
          let stream := loop >>- repeatM _
          pure (F.mmap id stream)
        } else pure []
      }) i := by {
        simp [main, pure, return, g__VERIFIER_nondet_int]
      }
    have : (F.mmap id (main >>= init)).i = F.mmap id (init (main)).i := by {
      simp [F, init, pure, return, main]
    }
    have : F.mmap id (init (main)).i = F.mmap id (main i) := by {
      simp [init, pure, return, main]
    }
    have : F.mmap id (main i) = false := by {
      simp [F, main]
    }
    have : F.mmap id (main >>= init).i = false := by {
      simp [F, main]
    }
    have : p := F.mmap id (main >>= init).i ∧ p ∧ (p ∧ (main >>= init).next = main >>= init) := by {
      simp [F, LTL, p, main]
    }
    simp [this, p]
  }
}
